#!/usr/bin/env python3\n\"\"\"\nBTC Grid Bot — Intelligence Dashboard\n\nDisplay actionable recommendations based on trading patterns.\nUsage: python3 intelligence_dashboard.py [--days 14] [--json]\n\"\"\"\n\nimport argparse\nimport json\nimport sys\nfrom pathlib import Path\n\n# Add bot to path\nsys.path.insert(0, str(Path(__file__).parent))\n\nfrom core.intelligence import get_intelligence_report\n\n\ndef format_priority(priority):\n    \"\"\"Format priority with emoji.\"\"\"\n    return {\n        \"high\": \"🔴 HIGH\",\n        \"medium\": \"🟡 MED\",\n        \"low\": \"🟢 LOW\"\n    }.get(priority, priority.upper())\n\n\ndef print_recommendations(report):\n    \"\"\"Print recommendations in human-readable format.\"\"\"\n    status = report.get(\"status\")\n    \n    if status == \"insufficient_data\":\n        print(\"\\n⚠️ Insufficient data for recommendations\")\n        print(report.get(\"message\", \"\"))\n        return\n    elif status == \"error\":\n        print(\"\\n❌ Analysis failed\")\n        print(report.get(\"message\", \"\"))\n        return\n    \n    print(f\"\\n🧠 Intelligence Dashboard ({report.get('analysis_period_days', 0)} days)\")\n    print(\"=\" * 70)\n    \n    # Summary\n    summary = report.get(\"summary\", {})\n    print(f\"Sessions analyzed: {summary.get('total_sessions', 0)}\")\n    print(f\"Total PnL: ${summary.get('total_pnl', 0):.2f}\")\n    print(f\"Avg per session: ${summary.get('avg_pnl_per_session', 0):.3f}\")\n    print(f\"Win rate: {summary.get('win_rate', 0):.1%}\")\n    print(f\"Best/Worst: ${summary.get('best_session', 0):.2f} / ${summary.get('worst_session', 0):.2f}\")\n    \n    recommendations = report.get(\"recommendations\", [])\n    \n    if not recommendations:\n        print(\"\\n✅ No specific recommendations at this time.\")\n        print(\"Current performance patterns look healthy.\")\n        return\n    \n    print(\"\\n📋 Actionable Recommendations\")\n    print(\"=\" * 70)\n    \n    for i, rec in enumerate(recommendations, 1):\n        priority = format_priority(rec.get(\"priority\", \"medium\"))\n        title = rec.get(\"title\", \"Unknown recommendation\")\n        finding = rec.get(\"finding\", \"\")\n        recommendation = rec.get(\"recommendation\", \"\")\n        rec_type = rec.get(\"type\", \"unknown\")\n        \n        print(f\"\\n{i}. [{priority}] {title}\")\n        print(f\"   Finding: {finding}\")\n        print(f\"   Action: {recommendation}\")\n        \n        # Show relevant data\n        data = rec.get(\"data\", {})\n        if data and len(str(data)) < 200:\n            key_data = []\n            for k, v in data.items():\n                if isinstance(v, (int, float)):\n                    if \"rate\" in k or \"pnl\" in k:\n                        key_data.append(f\"{k}: {v:.3f}\")\n                    else:\n                        key_data.append(f\"{k}: {v}\")\n                elif isinstance(v, dict) and len(v) <= 3:\n                    key_data.append(f\"{k}: {v}\")\n            if key_data:\n                print(f\"   Data: {', '.join(key_data[:3])}\")\n    \n    print(\"\\n💡 Implementation Tips\")\n    print(\"=\" * 70)\n    \n    high_priority_recs = [r for r in recommendations if r.get(\"priority\") == \"high\"]\n    if high_priority_recs:\n        print(\"• Address HIGH priority recommendations first\")\n        for rec in high_priority_recs:\n            if rec.get(\"type\") == \"direction_bias\":\n                print(\"• Direction bias: Update analyst prompt or add direction weighting\")\n            elif rec.get(\"type\") == \"risk_management\":\n                print(\"• Risk management: Reduce position size immediately\")\n            elif rec.get(\"type\") == \"timing\":\n                print(\"• Timing: Deploy grids during higher volatility periods\")\n    else:\n        print(\"• Monitor medium priority items for trend confirmation\")\n        print(\"• Continue current strategy with awareness of identified patterns\")\n    \n    print(\"\\n🔄 Next Analysis\")\n    print(\"Run this command again after 3-5 more sessions for updated recommendations.\")\n\n\ndef print_config_suggestions(recommendations):\n    \"\"\"Print specific config file changes.\"\"\"\n    if not recommendations:\n        return\n    \n    print(\"\\n⚙️ Suggested Config Changes\")\n    print(\"=\" * 70)\n    \n    for rec in recommendations:\n        if rec.get(\"type\") == \"roll_frequency\" and rec.get(\"priority\") in [\"high\", \"medium\"]:\n            print(\"# In config.yml, under grid section:\")\n            print(\"grid:\")\n            print(\"  max_rolls_per_session: 1  # reduced from 2\")\n            print(\"\")\n        \n        elif rec.get(\"type\") == \"risk_management\" and rec.get(\"priority\") == \"high\":\n            print(\"# In capital section, reduce exposure:\")\n            print(\"capital:\")\n            print(\"  max_exposure_multiplier: 2.0  # reduced from 3.0\")\n            print(\"\")\n\n\ndef main():\n    parser = argparse.ArgumentParser(description='Grid bot intelligence dashboard')\n    parser.add_argument('--days', type=int, default=14, help='Days to analyze')\n    parser.add_argument('--json', action='store_true', help='Output raw JSON')\n    parser.add_argument('--config', action='store_true', help='Show config suggestions')\n    \n    args = parser.parse_args()\n    \n    try:\n        report = get_intelligence_report(days=args.days)\n        \n        if args.json:\n            print(json.dumps(report, indent=2))\n        else:\n            print_recommendations(report)\n            \n            if args.config:\n                print_config_suggestions(report.get(\"recommendations\", []))\n    \n    except Exception as e:\n        print(f\"\\n❌ Dashboard failed: {e}\")\n        sys.exit(1)\n\n\nif __name__ == '__main__':\n    main()\n